      <rect x="18" y="38" width="95" height="10" rx="5" fill={palette.accent} opacity="0.85" />
      {/* Origin dot */}
      <circle cx="18" cy="43" r="6" fill={palette.accent} />
      <circle cx="18" cy="43" r="2.5" fill={palette.dark} />
